3	import { makeDxfLinkTransform, type DxfPrimitiveQueryHit } from './dxfUnderlay';
4	
5	export type PickedWallLineSource = 'floor-edge' | 'dxf-line';
6	
7	export type PickedWallLine = {
8	  source: PickedWallLineSource;
