const dbgMove = await stateEval(() => {
  const st = window.__bimStore.getState();
  const hud = st.planHudMm;
  const floors = Object.values(st.elementsById).filter((e) => e.kind === 'floor');
  const walls = Object.values(st.elementsById).filter((e) => e.kind === 'wall');
  // Check floor boundary distances manually
  const point = { xMm: hud?.xMm ?? 0, yMm: hud?.yMm ?? 0 };
  const edgeDists = [];
  for (const fl of floors) {
    for (let i = 0; i < (fl.boundaryMm?.length ?? 0); i++) {
      const s = fl.boundaryMm[i], e = fl.boundaryMm[(i+1) % fl.boundaryMm.length];
      const dx = e.xMm - s.xMm, dy = e.yMm - s.yMm;
      const len2 = dx*dx + dy*dy;
      const t = len2 > 0 ? Math.max(0, Math.min(1, ((point.xMm-s.xMm)*dx+(point.yMm-s.yMm)*dy)/len2)) : 0;
      const dist = Math.hypot(point.xMm - (s.xMm+dx*t), point.yMm - (s.yMm+dy*t));
      edgeDists.push({ flId: fl.id.slice(-8), edge: i, dist: Math.round(dist), lvl: fl.levelId });
    }
  }
  return { planTool: st.planTool, activeLevelId: st.activeLevelId, hud, floorCount: floors.length, wallCount: walls.length, edgeDists: edgeDists.sort((a,b) => a.dist-b.dist).slice(0,6) };
});

