182	  const hud = st.planHudMm;
183	  const floors = Object.values(st.elementsById).filter((e) => e.kind === 'floor');
184	  const walls = Object.values(st.elementsById).filter((e) => e.kind === 'wall');
185	  // Check floor boundary distances manually
186	  const point = { xMm: hud?.xMm ?? 0, yMm: hud?.yMm ?? 0 };
187	  const edgeDists = [];
188	  for (const fl of floors) {
189	    for (let i = 0; i < (fl.boundaryMm?.length ?? 0); i++) {
190	      const s = fl.boundaryMm[i], e = fl.boundaryMm[(i+1) % fl.boundaryMm.length];
191	      const dx = e.xMm - s.xMm, dy = e.yMm - s.yMm;
192	      const len2 = dx*dx + dy*dy;
193	      const t = len2 > 0 ? Math.max(0, Math.min(1, ((point.xMm-s.xMm)*dx+(point.yMm-s.yMm)*dy)/len2)) : 0;
194	      const dist = Math.hypot(point.xMm - (s.xMm+dx*t), point.yMm - (s.yMm+dy*t));
195	      edgeDists.push({ flId: fl.id.slice(-8), edge: i, dist: Math.round(dist), lvl: fl.levelId });
196	    }
197	  }
