  // EDT-01 — grip drag takes priority over every other interaction.
  if (gripDragRef.current) {
    const rwGrip = rayToPlanMm(rnd, camNow, ev.clientX, ev.clientY);
    if (rwGrip) {
      const startMm = gripDragRef.current.startWorldMm;
