    {/* SKT-01 / SKT-02 / SKT-03 — Sketch authoring overlay. Active when one
        of the *-sketch tools is selected. Commits a Create<Kind> command on
        Finish and otherwise leaves the document untouched. */}
    {(planTool === 'floor-sketch' ||
