        planTool === 'ceiling-sketch' ||
        planTool === 'shaft-sketch' ||
        planTool === 'room-separation-sketch' ||
        planTool === 'masking-region') &&
      modelId &&
      lvlId ? (
        <>
          {planTool === 'roof-sketch' ? (
            <div
              className="pointer-events-auto absolute top-3 left-1/2 z-30 flex -translate-x-1/2 items-center gap-3 rounded-lg bg-[var(--surface-overlay,#1e2433)] px-4 py-2 shadow-lg"
              data-testid="roof-sketch-options"
            >
              <label className="flex items-center gap-2 text-xs text-[var(--text-secondary,#9ba3b2)]">
                Overhang
                <input
                  className="w-16 rounded bg-[var(--surface-input,#2a3147)] px-2 py-0.5 text-right text-xs text-[var(--text-primary,#e2e8f0)]"
                  data-testid="roof-sketch-overhang"
                  type="number"
                  min={0}
                  max={2000}
                  step={50}
                  value={roofSketchOverhangMm}
                  onChange={(e) => setRoofSketchOverhangMm(Number(e.target.value))}
                />
                <span className="text-[10px]">mm</span>
              </label>
              <label className="flex items-center gap-2 text-xs text-[var(--text-secondary,#9ba3b2)]">
                Slope
                <input
                  className="w-14 rounded bg-[var(--surface-input,#2a3147)] px-2 py-0.5 text-right text-xs text-[var(--text-primary,#e2e8f0)]"
                  data-testid="roof-sketch-slope"
                  type="number"
                  min={0}
                  max={75}
                  step={1}
                  value={roofSketchSlopeDeg}
                  onChange={(e) => setRoofSketchSlopeDeg(Number(e.target.value))}
                />
                <span className="text-[10px]">°</span>
              </label>
            </div>
          ) : null}
          <SketchCanvas
            modelId={modelId}
            levelId={lvlId}
            elementKind={
              planTool === 'roof-sketch'
                ? 'roof'
                : planTool === 'ceiling-sketch'
                  ? 'ceiling'
                  : planTool === 'shaft-sketch'
                    ? 'shaft'
                    : planTool === 'room-separation-sketch'
                      ? 'room_separation'
                      : planTool === 'masking-region'
                        ? 'masking_region'
                        : 'floor'
            }
            pointerToMmRef={sketchPointerToMmRef}
            mmToScreenRef={sketchMmToScreenRef}
            wallsForPicking={Object.values(elementsById)
              .filter(
                (el): el is Extract<Element, { kind: 'wall' }> =>
                  el.kind === 'wall' && (!lvlId || el.levelId === lvlId),
              )
              .map((w) => ({
                id: w.id,
                startMm: { xMm: w.start.xMm, yMm: w.start.yMm },
                endMm: { xMm: w.end.xMm, yMm: w.end.yMm },
                thicknessMm: w.thicknessMm,
              }))}
            floorTypeId={useBimStore.getState().activeFloorTypeId ?? undefined}
            extraOptions={
              planTool === 'masking-region' && activePlanViewId
                ? { hostViewId: activePlanViewId }
                : planTool === 'roof-sketch'
                  ? { overhangMm: roofSketchOverhangMm, slopeDeg: roofSketchSlopeDeg }
                  : undefined
            }
            onFinished={(createdId) => {
              setPlanTool('select');
              if (createdId) selectEl(createdId);
            }}
            onCancelled={() => setPlanTool('select')}
          />
        </>
      ) : null}"""

if old_sketch_block in content:
