68	async function postJson<T>(url: string, body: unknown): Promise<T> {
69	  const res = await fetch(url, {
70	    method: 'POST',
71	    headers: { 'content-type': 'application/json' },
72	    body: JSON.stringify(body),
73	  });
74	  const text = await res.text();
75	  if (!res.ok) {
76	    throw new Error(`${res.status} ${res.statusText}: ${text}`);
77	  }
78	  return text ? (JSON.parse(text) as T) : ({} as T);
79	}
